#include <stdio.h>

int findMaxProfit(int *prices, int n) {
    int minPrice = prices[0];
    int maxProfit = 0;
    for (int i = 1; i < n; ++i) {
        if (prices[i] < minPrice) {
            minPrice = prices[i];
        } else {
            int profit = prices[i] - minPrice;
            if (profit > maxProfit) maxProfit = profit;
        }
    }
    return maxProfit;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int prices[100000]; // maximum possible n
        for (int i = 0; i < n; ++i) {
            scanf("%d", &prices[i]);
        }
        printf("%d\n", findMaxProfit(prices, n));
    }
    return 0;
}

