#include <bits/stdc++.h>
using namespace std;

int findMaxProfit(const vector<int>& prices) {
    int minPrice = prices[0];
    int maxProfit = 0;
    for (size_t i = 1; i < prices.size(); ++i) {
        if (prices[i] < minPrice) minPrice = prices[i];
        else maxProfit = max(maxProfit, prices[i] - minPrice);
    }
    return maxProfit;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int n;
        cin >> n;
        vector<int> prices(n);
        for (int &x : prices) cin >> x;
        cout << findMaxProfit(prices) << '\n';
    }
    return 0;
}

